from gpio import *
from time import *
from ioeclient import *
from physical import *
from bluetooth import *
import math

state = 0
dstMac = "FFFF.FFFF.FFFF"
dstService = "{58c41a2f-5111-45b0-863c-0429591c81fd}"
btService = BluetoothService()

def main():
	setup()
	while True:
		sleep(3600)

def setup():
    IoEClient.setup({
        "type": "Portable Music Player",
        "states": [{
            "name": "On",
            "type": "bool",
            "controllable": True
        }]
    })

    IoEClient.onInputReceive(onInputReceiveDone)
    add_event_detect(0, detect)
    global state
    state = restoreProperty("state", 0)
    setState(state)

    Bluetooth.init()
    Bluetooth.setAcceptingPairRequest(True)
    Bluetooth.setDiscoverable(True)

    print(btService.start(dstService))

def detect():
    processData(customRead(0), False)

def onInputReceiveDone(analogInput):
    processData(analogInput, True)

def restoreProperty(propertyName, defaultValue):
    value = getDeviceProperty(getName(), propertyName)
    if  not (value is "" or value is None):
        if  type(defaultValue) is int :
            value = int(value)

        setDeviceProperty(getName(), propertyName, value)
        return value
    return defaultValue

def mouseEvent(pressed, x, y, firstPress):
    if firstPress:
    	if state == 1:
    		setState(0)
    	else:
    		setState(1)

def processData(data, bIsRemote):
    if len(data) <= 0 :
        return
    setState(int(data))

def setState(newState):
    global state
    state = newState

    if state is 0:
        digitalWrite(1, LOW)

        btService.send(dstMac, dstService, "")
    else:
        digitalWrite(1, HIGH)

        if dstMac:
            btService.send(dstMac, dstService, "/../Sounds/crickets.wav")

    IoEClient.reportStates(state)
    setDeviceProperty(getName(), "state", state)

def onPairRequestDone(mac, deviceName):
    print("accepting pair request: " + str(mac))
    Bluetooth.acceptPairRequest(mac, deviceName)

Bluetooth.onPairRequest(onPairRequestDone)

def onDevicePairDone(mac):
    print("paired: " + str(mac))

Bluetooth.onDevicePair(onDevicePairDone)

def onDeviceUnpairDone(mac):
    print("unpaired: " + str(mac))

Bluetooth.onDeviceUnpair(onDeviceUnpairDone)

def onDeviceConnectDone(mac):
    print("connected: " + str(mac))

Bluetooth.onDeviceConnect(onDeviceConnectDone)

def onDeviceDisconnectDone(mac):
    print("disconnected: " + str(mac))

Bluetooth.onDeviceDisconnect(onDeviceDisconnectDone)

if __name__ == "__main__":
    main()

var state = 0;
var dstMac = "FFFF.FFFF.FFFF";
var dstService = "{58c41a2f-5111-45b0-863c-0429591c81fd}";
var btService = new BluetoothService();

function setup()
{
	IoEClient.setup({
		type: "Portable Music Player",
		states: [{
			name: "On",
			type: "bool",
			controllable: true
		}]
	});

	IoEClient.onInputReceive = function(input) {
		processData(input, true);
	};

	attachInterrupt(0, function() {
		processData(customRead(0), false);
	});

	state = restoreProperty("state", 0);
	setState(state);

	Bluetooth.init();
	Bluetooth.setAcceptingPairRequest(true);
	Bluetooth.setDiscoverable(true);

    Serial.println(btService.start(dstService));
}



function restoreProperty(propertyName, defaultValue)
{
	var value = getDeviceProperty(getName(), propertyName);
	if ( !(value === "" || value == "undefined") ){
		if ( typeof(defaultValue) == "number" )
			value = Number(value);

		setDeviceProperty(getName(), propertyName, value);
		return value;
	}

	return defaultValue;
}



function mouseEvent(pressed, x, y, firstPress)
{
	if (firstPress)
		setState(state ? 0 : 1);
}

function processData(data, bIsRemote)
{
	if ( data.length <= 0  )
		return;
	setState(parseInt(data));
}

function setState(newState)
{
	state = newState;

	if ( state === 0 )
    {
		digitalWrite(1, LOW);

		btService.send(dstMac, dstService, "");
    }
	else
    {
		digitalWrite(1, HIGH);

        if (dstMac)
        	btService.send(dstMac, dstService, "/../Sounds/crickets.wav");
    }

	IoEClient.reportStates(state);
	setDeviceProperty(getName(), "state", state);
}

Bluetooth.onPairRequest = function(mac, deviceName) {
	Serial.println("accepting pair request: " + mac);
	Bluetooth.acceptPairRequest(mac, deviceName);
};

Bluetooth.onDevicePair = function(mac) {
	Serial.println("paired: " + mac);
};

Bluetooth.onDeviceUnpair = function(mac) {
	Serial.println("unpaired: " + mac);
};

Bluetooth.onDeviceConnect = function(mac) {
	Serial.println("connected: " + mac);
};

Bluetooth.onDeviceDisconnect = function(mac) {
	Serial.println("disconnected: " + mac);
};

